        store.apply_spawn_groups_like_cpp(
            &mut templates,
            [crate::spawn::SpawnGroupMemberRow {
                group_id: group.group_id,
                spawn_type: SpawnObjectType::Creature as u8,
                spawn_id: 30,
            }],
        );
