        assert_eq!(
            map.get_typed_player(player_guid)
                .unwrap()
                .active_data()
                .farsight_object,
            dynamic_object_guid
        );

        let drain = map.remove_all_objects_in_remove_list_like_cpp();

        assert_eq!(drain.processed, 1);
        assert_eq!(drain.removed, 1);
        assert_eq!(map.objects_to_remove_count_like_cpp(), 0);
